/**
 * Get product by id (number) - follows dual ID system
 * SECURITY: Enforces merchant isolation to prevent cross-tenant access
 */
export async function getProductById(id: number, merchantId: number) {
  // Find merchant by id
  const merchant = await prisma.merchant.findUnique({
    where: { id: merchantId },
    select: { id: true }
  });
  
  if (!merchant) {
    throw new Error(`Merchant with id ${merchantId} not found`);
  }

  return await prisma.product.findFirst({
    where: { 
      id,
      merchantId: merchant.id // Use CUID for merchant isolation
    },
    include: {
      merchant: {
        select: {
          id: true,
          name: true,
        },
      },
      category: {
        select: {
          id: true,
          name: true,
        },
      },
      outletStock: {
        select: {
          id: true,
          stock: true,
          available: true,
          renting: true,
          outlet: {
            select: {
      id: true,
              name: true,
              address: true,
            },
          },
        },
      },
    },
  });
}

