/**
 * Build order by clause for product queries
 */
function buildProductOrderByClause(sortBy?: string, sortOrder?: string): any {
  const validSortFields = [
    'createdAt', 'updatedAt', 'name', 'rentPrice', 'salePrice', 'totalStock'
  ];
  
  const field = validSortFields.includes(sortBy || '') ? sortBy : 'createdAt';
  const order = sortOrder === 'asc' ? 'asc' : 'desc';
  
  return { [field as string]: order };
}

/**
 * Search products - follows dual ID system
 * Input: ids (numbers), Output: ids (numbers)
 */
export async function searchProducts(filters: ProductSearchFilter) {
  const {
    merchantId,
    outletId,
    categoryId,
    search,
    q, // Add q parameter support
    page = 1,
    limit = 20,
    offset, // Add offset support
    isActive = true,
    available,
    minPrice,
    maxPrice,
    sortBy,
    sortOrder
  } = filters;

  // Use offset if provided, otherwise calculate from page
  const skip = offset !== undefined ? offset : (page - 1) * limit;

  // Build where clause
  const where: any = {
    isActive,
  };

  if (merchantId) {
    // Find merchant by id
    const merchant = await prisma.merchant.findUnique({
      where: { id: merchantId },
      select: { id: true }
    });
    
    if (merchant) {
      where.merchantId = merchant.id; // Use CUID
    }
  }

  if (categoryId) {
    // Find category by id
    const category = await prisma.category.findUnique({
      where: { id: categoryId },
      select: { id: true }
    });
    
    if (category) {
      where.categoryId = category.id; // Use number ID (Category uses Int id)
    }
  }

  // Handle search query - use 'q' parameter first, fallback to 'search' for backward compatibility
  // Support word-by-word search: "Áo dài đỏ" matches products with ALL words: "ao", "dai", AND "do"
  // Case-insensitive and diacritics-insensitive
  // AND logic: product must contain ALL words in name or description
  const searchQuery = q || search;
  if (searchQuery) {
    const searchTerm = searchQuery.trim();
    
    // Split query into individual words
    const words = searchTerm.split(/\s+/).filter((word: string) => word.length > 0);
    
    if (words.length > 0) {
      const andConditions: any[] = [];
      
      // For each word, create condition: word must appear in name OR description
      // ALL words must be present (AND logic)
      for (const word of words) {
        const normalizedWord = removeVietnameseDiacritics(word.toLowerCase());
        const originalWord = word.toLowerCase();
        
        // Word must be in name OR description (with diacritics)
        const wordConditions: any[] = [
          { name: { contains: originalWord, mode: 'insensitive' } },
          { description: { contains: originalWord, mode: 'insensitive' } }
        ];
        
        // Add normalized word search if different from original
        if (normalizedWord !== originalWord) {
          wordConditions.push(
            { name: { contains: normalizedWord, mode: 'insensitive' } },
            { description: { contains: normalizedWord, mode: 'insensitive' } }
          );
        }
        
        // Each word must be found (AND logic)
        andConditions.push({ OR: wordConditions });
      }
      
      // Barcode is exact match (not word-by-word) - add as OR condition
      const barcodeCondition = { barcode: { equals: searchTerm } };
      
      // Product matches if: (ALL words found) OR (barcode matches)
      where.OR = [
        { AND: andConditions },
        barcodeCondition
      ];
    }
  }

  // If outletId is specified, filter products by outlet (include all products at that outlet, including qty = 0)
  // Only filter by stock > 0 if available filter is explicitly set to true
  if (outletId) {
    // Find outlet by id
    const outlet = await prisma.outlet.findUnique({
      where: { id: outletId },
      select: { id: true }
    });
    
    if (outlet) {
      // If available filter is not set or is false, show all products at outlet (including qty = 0)
      // If available filter is true, only show products with stock > 0
      if (available === true) {
      where.outletStock = {
        some: {
          outletId: outlet.id, // Use CUID
            available: { gt: 0 }
          }
        };
      } else {
        // Show all products at outlet, including those with qty = 0
        where.outletStock = {
          some: {
            outletId: outlet.id // Use CUID, no stock filter
        }
      };
      }
    }
  }

  // Add availability filter (only if outletId is not specified, as outletId filter already handles available)
  // Only filter when available=true is explicitly set - show all products (including qty = 0 and < 0) otherwise
  if (available === true && !outletId) {
      where.outletStock = {
        some: {
          available: { gt: 0 }
        }
      };
        }
  // If available=false or undefined, don't filter - show all products

  // Add price range filters
  if (minPrice !== undefined || maxPrice !== undefined) {
    where.rentPrice = {};
    if (minPrice !== undefined) where.rentPrice.gte = minPrice;
    if (maxPrice !== undefined) where.rentPrice.lte = maxPrice;
  }

  const [products, total] = await Promise.all([
    prisma.product.findMany({
      where,
      select: {
      id: true,
        name: true,
        description: true,
        barcode: true,
        totalStock: true,
        rentPrice: true,
        salePrice: true,
        deposit: true,
        images: true,
        isActive: true,
        createdAt: true,
        updatedAt: true,
        category: {
          select: {
      id: true,
            name: true
          }
        },
        merchant: {
          select: {
      id: true,
            name: true
          }
        },
        outletStock: {
          select: {
            id: true,
            stock: true,
            available: true,
            renting: true,
            outlet: {
              select: {
      id: true,
                name: true,
                address: true
              }
            }
          }
        }
      },
      orderBy: buildProductOrderByClause(sortBy, sortOrder),
      take: limit,
      skip: skip
    }),
    prisma.product.count({ where })
  ]);

  // Transform to match expected types
  const transformedProducts = products.map((product: any) => {
    // Calculate total renting from all outlets
    const totalRenting = product.outletStock.reduce((sum: number, stock: any) => sum + (stock.renting || 0), 0);
    // Calculate available at product level: totalStock - totalRenting
    const available = Math.max(0, (product.totalStock || 0) - totalRenting);
    
    return {
      id: product.id, // Return id (number) for external use
      name: product.name,
      description: product.description,
      barcode: product.barcode,
      totalStock: product.totalStock,
      available: available, // Product-level available = totalStock - sum(renting from all outlets)
      rentPrice: product.rentPrice,
      salePrice: product.salePrice,
      costPrice: product.costPrice, // Include costPrice (giá vốn)
      deposit: product.deposit,
      images: product.images,
      isActive: product.isActive,
      createdAt: product.createdAt,
      updatedAt: product.updatedAt,
      category: {
        id: product.category.id, // Return id (number)
        name: product.category.name,
      },
      merchant: {
        id: product.merchant.id, // Return id (number)
        name: product.merchant.name,
      },
      outletStock: product.outletStock.map((stock: any) => ({
        id: stock.id, // Keep CUID for internal use
        stock: stock.stock,
        // Calculate available = stock - renting (ensure it's always correct)
        available: Math.max(0, (stock.stock || 0) - (stock.renting || 0)),
        renting: stock.renting,
        outlet: {
          id: stock.outlet.id, // Return id (number)
          name: stock.outlet.name,
          address: stock.outlet.address,
        },
      })),
    };
  });

  return {
    products: transformedProducts,
    total,
    page: offset !== undefined ? Math.floor(offset / limit) + 1 : page,
    limit,
    offset: skip,
    hasMore: skip + limit < total,
    totalPages: Math.ceil(total / limit),
  };
}

