/**
 * Update product stock - follows dual ID system
 */
export async function updateProductStock(
  productId: number,
  outletId: number,
  stockChange: number
): Promise<any> {
  // Find product by id
  const product = await prisma.product.findUnique({
    where: { id: productId },
    select: { id: true }
  });
  
  if (!product) {
    throw new Error(`Product with id ${productId} not found`);
  }

  // Find outlet by id
  const outlet = await prisma.outlet.findUnique({
    where: { id: outletId },
    select: { id: true }
  });
  
  if (!outlet) {
    throw new Error(`Outlet with id ${outletId} not found`);
  }

  // Update or create outlet stock
  const outletStock = await prisma.outletStock.upsert({
    where: {
      productId_outletId: {
        productId: product.id, // Use CUID
        outletId: outlet.id, // Use CUID
      },
    },
    update: {
      stock: { increment: stockChange },
      available: { increment: stockChange },
    },
    create: {
      productId: product.id, // Use CUID
      outletId: outlet.id, // Use CUID
      stock: stockChange,
      available: stockChange,
      renting: 0,
    },
  });

  // Sync Product.totalStock = sum of all OutletStock.stock
  if (stockChange !== 0) {
    await syncProductTotalStock(productId);
  }

  return outletStock;
}

/**
 * Sync Product.totalStock = sum of all OutletStock.stock for this product
 * This ensures Product.totalStock always equals the sum of all outlet stocks
 */
export async function syncProductTotalStock(productId: number): Promise<void> {
  // Find product by id
  const product = await prisma.product.findUnique({
    where: { id: productId },
    select: { id: true }
  });
  
  if (!product) {
    throw new Error(`Product with id ${productId} not found`);
  }

  // Get all outlet stock for this product
  const allOutletStock = await prisma.outletStock.findMany({
    where: { productId: product.id },
    select: { stock: true }
  });
  
  // Calculate total stock = sum of all outlet stocks
  const totalStock = allOutletStock.reduce((sum: number, os: { stock: number }): number => sum + os.stock, 0);
  
  // Update Product.totalStock
  await prisma.product.update({
    where: { id: product.id },
    data: { totalStock }
  });
  
  console.log(`✅ Synced Product.totalStock: ${totalStock} (sum of ${allOutletStock.length} outlets) for product ${productId}`);
}

/**
 * Sync OutletStock.available field to ensure it equals stock - renting
 * This ensures data consistency after any stock or renting updates
 */
export async function syncOutletStockAvailable(
  productId: number,
  outletId: number
): Promise<void> {
  // Find product and outlet by id
  const product = await prisma.product.findUnique({
    where: { id: productId },
    select: { id: true }
  });
  
  if (!product) {
    throw new Error(`Product with id ${productId} not found`);
  }

  const outlet = await prisma.outlet.findUnique({
    where: { id: outletId },
    select: { id: true }
  });
  
  if (!outlet) {
    throw new Error(`Outlet with id ${outletId} not found`);
  }

  // Get current outlet stock
  const outletStock = await prisma.outletStock.findUnique({
    where: {
      productId_outletId: {
        productId: product.id,
        outletId: outlet.id,
      },
    },
  });

  if (!outletStock) {
    console.warn(`OutletStock not found for product ${productId} and outlet ${outletId}`);
    return;
  }

  // Recalculate available = stock - renting
  // Note: Reserved orders are NOT counted in available calculation.
  // Reserved items are still in stock physically, just reserved temporarily.
  // For accurate date-based availability with reserved conflicts, use the availability API.
  const calculatedAvailable = Math.max(0, outletStock.stock - outletStock.renting);

  // Update if different
  if (outletStock.available !== calculatedAvailable) {
    await prisma.outletStock.update({
      where: { id: outletStock.id },
      data: { available: calculatedAvailable },
    });
    console.log(`✅ Synced OutletStock.available: ${outletStock.available} → ${calculatedAvailable} (product ${productId}, outlet ${outletId})`);
  }
}

/**
 * Update OutletStock when order status changes
 * Handles both RENT and SALE orders according to Odoo best practices:
 * - RENT: Uses renting field (temporary), stock doesn't change
 * - SALE: Decreases stock permanently (sold, not returned)
 */
export async function updateOutletStockForOrder(
  orderId: number,
  oldStatus: string | null,
  newStatus: string,
  orderType: 'RENT' | 'SALE',
  outletId: number,
  orderItems: Array<{ productId: number; quantity: number }>
): Promise<void> {
  console.log(`🔄 Updating outlet stock for order ${orderId}: ${oldStatus} → ${newStatus} (${orderType})`);

  // Find outlet by id
  const outlet = await prisma.outlet.findUnique({
    where: { id: outletId },
    select: { id: true }
  });
  
  if (!outlet) {
    throw new Error(`Outlet with id ${outletId} not found`);
  }

  // Process each order item
  for (const item of orderItems) {
    // Allow negative quantity (user requirement)
    if (!item.productId || item.quantity === undefined || item.quantity === null) {
      console.warn(`⚠️ Skipping invalid order item:`, item);
      continue;
    }

    // Find product by id
    const product = await prisma.product.findUnique({
      where: { id: item.productId },
      select: { id: true }
    });

    if (!product) {
      console.warn(`⚠️ Product ${item.productId} not found, skipping stock update`);
      continue;
    }

    // Get or create outlet stock
    let outletStock = await prisma.outletStock.findUnique({
      where: {
        productId_outletId: {
          productId: product.id,
          outletId: outlet.id,
        },
      },
    });

    if (!outletStock) {
      console.warn(`⚠️ OutletStock not found for product ${item.productId} and outlet ${outletId}, creating...`);
      outletStock = await prisma.outletStock.create({
        data: {
          productId: product.id,
          outletId: outlet.id,
          stock: 0,
          available: 0,
          renting: 0,
        },
      });
    }

    // Determine stock changes based on order type and status transition
    let stockChange = 0;
    let rentingChange = 0;
    let availableChange = 0;

    if (orderType === ORDER_TYPE.SALE) {
      // SALE orders: Permanently decrease stock when COMPLETED/PICKUPED
      if (newStatus === ORDER_STATUS.COMPLETED || newStatus === ORDER_STATUS.PICKUPED) {
        // Only decrease if wasn't already completed/pickuped
        if (oldStatus !== ORDER_STATUS.COMPLETED && oldStatus !== ORDER_STATUS.PICKUPED) {
          stockChange = -item.quantity;
          availableChange = -item.quantity;
          console.log(`📉 SALE order ${orderId}: Decreasing stock by ${item.quantity} for product ${item.productId}`);
        }
      } else if (newStatus === ORDER_STATUS.CANCELLED) {
        // Rollback stock if was previously completed/pickuped
        if (oldStatus === ORDER_STATUS.COMPLETED || oldStatus === ORDER_STATUS.PICKUPED) {
          stockChange = item.quantity;
          availableChange = item.quantity;
          console.log(`📈 SALE order ${orderId}: Rolling back stock by ${item.quantity} for product ${item.productId}`);
        }
      }
      // RESERVED status doesn't change stock (just reserved, not sold yet)
    } else if (orderType === ORDER_TYPE.RENT) {
      // RENT orders: Use renting field (temporary), stock doesn't change
      if (newStatus === ORDER_STATUS.RESERVED) {
        // Reserve: No change to stock/renting/available (items still in stock)
        // Reserved is only checked in availability API with date conflicts
        // Only if not already reserved
        if (oldStatus !== ORDER_STATUS.RESERVED && oldStatus !== ORDER_STATUS.PICKUPED) {
          // No stock/renting/available change - reserved items are still physically in stock
          console.log(`🔒 RENT order ${orderId}: Reserving ${item.quantity} for product ${item.productId} (items still in stock)`);
        }
      } else if (newStatus === ORDER_STATUS.PICKUPED) {
        // Pickup: Increase renting, decrease available (if not already picked up)
        if (oldStatus !== ORDER_STATUS.PICKUPED) {
          if (oldStatus === ORDER_STATUS.RESERVED) {
            // From RESERVED: renting increases, available decreases
            rentingChange = item.quantity;
            availableChange = -item.quantity;
          } else {
            // From other status (e.g., directly to PICKUPED): both renting and available change
            rentingChange = item.quantity;
            availableChange = -item.quantity;
          }
          console.log(`📤 RENT order ${orderId}: Picking up ${item.quantity} for product ${item.productId}`);
        }
      } else if (newStatus === ORDER_STATUS.RETURNED) {
        // Return: Decrease renting, increase available
        if (oldStatus === ORDER_STATUS.PICKUPED) {
          rentingChange = -item.quantity;
          availableChange = item.quantity;
          console.log(`📥 RENT order ${orderId}: Returning ${item.quantity} for product ${item.productId}`);
        }
      } else if (newStatus === ORDER_STATUS.CANCELLED) {
        // Cancel: Rollback based on previous status
        if (oldStatus === ORDER_STATUS.PICKUPED) {
          // Was picked up: rollback renting and available
          rentingChange = -item.quantity;
          availableChange = item.quantity;
          console.log(`↩️ RENT order ${orderId}: Cancelling pickup, rolling back ${item.quantity} for product ${item.productId}`);
        } else if (oldStatus === ORDER_STATUS.RESERVED) {
          // Was only reserved: no rollback needed (items were still in stock)
          // Reserved items don't affect available, so no change needed
          console.log(`↩️ RENT order ${orderId}: Cancelling reservation for product ${item.productId} (items were still in stock)`);
        }
      }
    }

    // Apply changes if any
    if (stockChange !== 0 || rentingChange !== 0 || availableChange !== 0) {
      const updateData: any = {};
      
      // Use increment for stock and renting
      if (stockChange !== 0) {
        updateData.stock = { increment: stockChange };
      }
      
      if (rentingChange !== 0) {
        updateData.renting = { increment: rentingChange };
      }

      // Calculate final available value: available = stock - renting
      // Note: Reserved orders are NOT counted in available calculation here.
      // Reserved items are still in stock physically, just reserved temporarily.
      // For accurate date-based availability with reserved conflicts, use the availability API.
      const newStock = outletStock.stock + stockChange;
      const newRenting = outletStock.renting + rentingChange;
      
      // Calculate available: stock - renting (reserved items are still in stock)
      const finalAvailable = Math.max(0, newStock - newRenting);
      updateData.available = finalAvailable;

      await prisma.outletStock.update({
        where: { id: outletStock.id },
        data: updateData,
      });

      console.log(`✅ Updated OutletStock for product ${item.productId}, outlet ${outletId}:`, {
        stockChange,
        rentingChange,
        availableChange,
        newStock,
        newRenting,
        newAvailable: finalAvailable,
      });

      // Sync Product.totalStock = sum of all OutletStock.stock for this product
      // Only sync if stock changed (SALE orders - permanent stock reduction)
      if (stockChange !== 0) {
        await syncProductTotalStock(item.productId);
      }
    }
  }
}

/**
 * Delete product - follows dual ID system
 * Input: id (number), Output: deleted product data
 */
export async function deleteProduct(id: number): Promise<any> {
  // Find product by id
  const product = await prisma.product.findUnique({
    where: { id },
    include: {
      category: {
        select: {
          id: true,
          name: true,
        },
      },
      merchant: {
        select: {
          id: true,
          name: true,
        },
      },
    },
  });
  
  if (!product) {
    throw new Error(`Product with id ${id} not found`);
  }

  // Delete the product (this will cascade to outletStock due to Prisma schema)
  const deletedProduct = await prisma.product.delete({
    where: { id },
    include: {
      category: {
        select: {
          id: true,
          name: true,
        },
      },
      merchant: {
        select: {
          id: true,
          name: true,
        },
      },
    },
  });

  // Transform to match expected types
  return {
    id: deletedProduct.id,
    name: deletedProduct.name,
    description: deletedProduct.description,
    barcode: deletedProduct.barcode,
    totalStock: deletedProduct.totalStock,
    rentPrice: deletedProduct.rentPrice,
    salePrice: deletedProduct.salePrice,
    deposit: deletedProduct.deposit,
    images: deletedProduct.images,
    isActive: deletedProduct.isActive,
    createdAt: deletedProduct.createdAt,
    updatedAt: deletedProduct.updatedAt,
    category: {
      id: deletedProduct.category.id,
      name: deletedProduct.category.name,
    },
    merchant: {
      id: deletedProduct.merchant.id,
      name: deletedProduct.merchant.name,
    },
  };
}

