export const simplifiedProducts = {
  /**
   * Find product by ID (simplified API)
   */
  findById: async (id: number) => {
    return await prisma.product.findUnique({
      where: { id },
      include: {
        merchant: { select: { id: true, name: true } },
        category: { select: { id: true, name: true } },
        outletStock: {
          include: {
            outlet: { select: { id: true, name: true, address: true } }
          }
        }
      }
    });
  },

  /**
   * Find product by barcode (simplified API)
   */
  findByBarcode: async (barcode: string) => {
    return await prisma.product.findUnique({
      where: { barcode },
      include: {
        merchant: { select: { id: true, name: true } },
        category: { select: { id: true, name: true } },
        outletStock: {
          include: {
            outlet: { select: { id: true, name: true } }
          }
        }
      }
    });
  },

  /**
   * Find multiple products by IDs (batch fetch - optimized for performance)
   */
  findByIds: async (ids: number[]) => {
    if (ids.length === 0) return [];
    
    return await prisma.product.findMany({
      where: { id: { in: ids } },
      include: {
        merchant: { select: { id: true, name: true } },
        category: { select: { id: true, name: true } },
        outletStock: {
          include: {
            outlet: { select: { id: true, name: true, address: true } }
          }
        }
      }
    });
  },

  /**
   * Create new product (simplified API)
   */
  create: async (data: any) => {
    try {
      // Get merchant ID for default category fallback
      const merchantId = data.merchant?.connect?.id;
      
      // Check if category is provided (either via categoryId or category.connect)
      const providedCategoryId = data.categoryId || data.category?.connect?.id;
      
      // If category is provided, validate it
      if (providedCategoryId) {
        const category = await prisma.category.findUnique({
          where: { id: providedCategoryId },
          select: { id: true, merchantId: true, isActive: true, name: true }
        });
        
        if (!category) {
          throw new Error(`Category with id ${providedCategoryId} not found`);
        }
        
        if (!category.isActive) {
          throw new Error(`Category "${category.name}" (id: ${providedCategoryId}) is not active`);
        }
        
        // Validate merchant match if merchant is provided
        if (merchantId && category.merchantId !== merchantId) {
          throw new Error(`Category "${category.name}" (id: ${providedCategoryId}) does not belong to merchant ${merchantId}`);
        }
        
        // Ensure category.connect is set (convert categoryId to connect format if needed)
        if (!data.category?.connect) {
          data.category = { connect: { id: providedCategoryId } };
        }
      } else if (merchantId) {
        // No category provided, use default category
        const defaultCategory = await getOrCreateDefaultCategory(merchantId);
        data.category = { connect: { id: defaultCategory.id } };
      }
      
      // Create product
      const product = await prisma.product.create({
        data,
        include: {
          merchant: { select: { id: true, name: true } },
          category: { select: { id: true, name: true } },
          outletStock: {
            include: {
              outlet: { select: { id: true, name: true } }
            }
          }
        }
      });
      
      return product;
    } catch (error) {
      console.error('❌ Error in simplifiedProducts.create:', error);
      throw error;
    }
  },

  /**
   * Update product (simplified API)
   */
  update: async (id: number, data: any) => {
    return await prisma.product.update({
      where: { id },
      data,
      include: {
        merchant: { select: { id: true, name: true } },
        category: { select: { id: true, name: true } },
        outletStock: {
          include: {
            outlet: { select: { id: true, name: true } }
          }
        }
      }
    });
  },

  /**
   * Delete product (soft delete) (simplified API)
   */
  delete: async (id: number) => {
    return await prisma.product.update({
      where: { id },
      data: { isActive: false }
    });
  },

  /**
   * Find first product matching criteria (simplified API)
   */
  findFirst: async (whereClause: any) => {
    // Handle both direct where clause and object with where property
    const where = whereClause?.where || whereClause || {};
    return await prisma.product.findFirst({
      where,
      include: {
        merchant: { select: { id: true, name: true } },
        category: { select: { id: true, name: true } },
        outletStock: {
          include: {
            outlet: { select: { id: true, name: true } }
          }
        }
      }
    });
  },

  /**
   * Get product statistics (simplified API)
   */
  getStats: async (whereClause?: any) => {
    // Handle both direct where clause and object with where property
    const where = whereClause?.where || whereClause || {};
    return await prisma.product.count({ where });
  },

  /**
   * Search products with simple filters (simplified API)
   * Handles conversion of public IDs (numbers) to CUIDs for database queries
   */
  search: async (filters: any) => {
    const { page = 1, limit = 20, sortBy, sortOrder, ...whereFilters } = filters;
    const skip = (page - 1) * limit;

    // Build where clause
    const where: any = {
      isActive: whereFilters.isActive !== undefined ? whereFilters.isActive : true
    };
    
    // Convert merchantId (public ID) to CUID
    if (whereFilters.merchantId) {
      const merchant = await prisma.merchant.findUnique({
        where: { id: whereFilters.merchantId },
        select: { id: true }
      });
      if (merchant) {
        where.merchantId = merchant.id; // Use CUID
      } else {
        // Merchant not found, return empty result
        return {
          data: [],
          total: 0,
          page,
          limit,
          hasMore: false
        };
      }
    }
    
    // Convert categoryId (public ID) to CUID
    if (whereFilters.categoryId) {
      const category = await prisma.category.findUnique({
        where: { id: whereFilters.categoryId },
        select: { id: true }
      });
      if (category) {
        where.categoryId = category.id; // Use number ID (Category uses Int id)
      } else {
        // Category not found, return empty result
        return {
          data: [],
          total: 0,
          page,
          limit,
          hasMore: false
        };
      }
    }
    
    // Convert outletId (public ID) to CUID and filter by outlet stock
    // Show all products at outlet (including qty = 0) unless available filter is explicitly set to true
    if (whereFilters.outletId) {
      const outlet = await prisma.outlet.findUnique({
        where: { id: whereFilters.outletId },
        select: { id: true }
      });
      if (outlet) {
        // If available filter is not set or is false, show all products at outlet (including qty = 0)
        // If available filter is true, only show products with available > 0
        if (whereFilters.available === true) {
        where.outletStock = {
          some: {
            outletId: outlet.id, // Use CUID
              available: { gt: 0 }
          }
        };
        } else {
          // Show all products at outlet, including those with qty = 0
          where.outletStock = {
            some: {
              outletId: outlet.id // Use CUID, no stock filter
            }
          };
        }
      } else {
        // Outlet not found, return empty result
        return {
          data: [],
          total: 0,
          page,
          limit,
          hasMore: false
        };
      }
    }
    
    // Availability filter (only if outletId is not specified, as outletId filter already handles available)
    // Only filter when available=true is explicitly set - show all products (including qty = 0 and < 0) otherwise
    if (whereFilters.available === true && !whereFilters.outletId) {
        where.outletStock = {
          some: {
            available: { gt: 0 }
          }
        };
          }
    // If available=false or undefined, don't filter - show all products
    
    // Text search - word-by-word search: "Áo dài đỏ" matches products with ALL words: "ao", "dai", AND "do"
    // Case-insensitive and diacritics-insensitive
    // AND logic: product must contain ALL words in name or description
    if (whereFilters.search) {
      const searchTerm = whereFilters.search.trim();
      
      // Split query into individual words
      const words = searchTerm.split(/\s+/).filter((word: string) => word.length > 0);
      
      if (words.length > 0) {
        const andConditions: any[] = [];
        
        // For each word, create condition: word must appear in name OR description
        // ALL words must be present (AND logic)
        for (const word of words) {
          const normalizedWord = removeVietnameseDiacritics(word.toLowerCase());
          const originalWord = word.toLowerCase();
          
          // Word must be in name OR description (with diacritics)
          const wordConditions: any[] = [
            { name: { contains: originalWord, mode: 'insensitive' } },
            { description: { contains: originalWord, mode: 'insensitive' } }
          ];
          
          // Add normalized word search if different from original
          if (normalizedWord !== originalWord) {
            wordConditions.push(
              { name: { contains: normalizedWord, mode: 'insensitive' } },
              { description: { contains: normalizedWord, mode: 'insensitive' } }
            );
          }
          
          // Each word must be found (AND logic)
          andConditions.push({ OR: wordConditions });
        }
        
        // Barcode is exact match (not word-by-word) - add as OR condition
        const barcodeCondition = { barcode: { contains: searchTerm, mode: 'insensitive' } };
        
        // Product matches if: (ALL words found) OR (barcode matches)
        where.OR = [
          { AND: andConditions },
          barcodeCondition
        ];
      }
    }

    // Price range
    if (whereFilters.minPrice !== undefined || whereFilters.maxPrice !== undefined) {
      where.rentPrice = {};
      if (whereFilters.minPrice !== undefined) where.rentPrice.gte = whereFilters.minPrice;
      if (whereFilters.maxPrice !== undefined) where.rentPrice.lte = whereFilters.maxPrice;
    }

    // Build orderBy clause
    const orderBy = buildProductOrderByClause(sortBy, sortOrder);

    const [products, total] = await Promise.all([
      prisma.product.findMany({
        where,
        include: {
          merchant: { select: { id: true, name: true } },
          category: { select: { id: true, name: true } },
          outletStock: {
            include: {
              outlet: { select: { id: true, name: true, address: true } }
            }
          }
        },
        orderBy,
        skip,
        take: limit
      }),
      prisma.product.count({ where })
    ]);

    return {
      data: products,
      total,
      page,
      limit,
      hasMore: skip + limit < total
    };
  },

  count: async (options?: { where?: any }) => {
    const where = options?.where || {};
    return await prisma.product.count({ where });
  }
};
